import pennylane as qml
n = 3
dev = qml.device('default.qubit', wires=n+1)
@qml.qnode(dev)
def deutsch_jozsa():
    qml.PauliX(wires=n)
    for i in range(n+1):
        qml.Hadamard(wires=i)
    qml.CNOT(wires=[0, n])
    for i in range(n):
        qml.Hadamard(wires=i)
    return qml.probs(wires=range(n))

